+        let content = "999 (zombie_child) Z 1000 999 999 0 -1";
+        let result = parse_stat(content, 999);
+        assert!(result.is_ok());
+        let (ppid, comm) = result.unwrap();
+        assert_eq!(ppid, 1000);
+        assert_eq!(comm, "zombie_child");
